'use client';

import type { VocabularyWordDto } from '@soenglish/shared-types';
import { Badge, Button, EmptyStateCard, Field, ProgressHeader, SegmentedControl, StatTile } from '../../components/ui';
import styles from './page.module.scss';

export function VocabularyModeToggle({
  mode,
  onChange,
}: {
  mode: 'list' | 'flashcard';
  onChange: (mode: 'list' | 'flashcard') => void;
}) {
  return (
    <SegmentedControl
      value={mode}
      onValueChange={onChange}
      ariaLabel="Vocabulary mode"
      className={styles.modeToggle}
      optionClassName={styles.modeBtn}
      activeOptionClassName={styles.modeActive}
      options={[
        {
          value: 'list',
          label: 'List',
          icon: (
            <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
              <path d="M2 4h12M2 8h12M2 12h8" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" />
            </svg>
          ),
        },
        {
          value: 'flashcard',
          label: 'Flashcards',
          icon: (
            <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
              <rect x="2" y="4" width="12" height="9" rx="1.5" stroke="currentColor" strokeWidth="1.5" />
              <path d="M5 4V3a1 1 0 0 1 1-1h4a1 1 0 0 1 1 1v1" stroke="currentColor" strokeWidth="1.5" />
            </svg>
          ),
        },
      ]}
    />
  );
}

export function VocabularyStatsRow({
  total,
  stats,
  onFilter,
}: {
  total: number;
  stats: { new: number; learning: number; known: number };
  onFilter: (value: string) => void;
}) {
  return (
    <div className={styles.statsRow}>
      <StatTile className={styles.statChip} interactive onClick={() => onFilter('all')} label="Total" labelClassName={styles.statLbl} value={total} valueClassName={styles.statNum} />
      <StatTile className={`${styles.statChip} ${styles.statBlue}`} interactive onClick={() => onFilter('new')} label="New" labelClassName={styles.statLbl} value={stats.new} valueClassName={styles.statNum} />
      <StatTile className={`${styles.statChip} ${styles.statAmber}`} interactive onClick={() => onFilter('learning')} label="Learning" labelClassName={styles.statLbl} value={stats.learning} valueClassName={styles.statNum} />
      <StatTile className={`${styles.statChip} ${styles.statGreen}`} interactive onClick={() => onFilter('known')} label="Known" labelClassName={styles.statLbl} value={stats.known} valueClassName={styles.statNum} />
    </div>
  );
}

export function VocabularyListSection({
  search,
  setSearch,
  categories,
  filter,
  setFilter,
  filtered,
  setWords,
}: {
  search: string;
  setSearch: (value: string) => void;
  categories: string[];
  filter: string;
  setFilter: (value: string) => void;
  filtered: VocabularyWordDto[];
  setWords: React.Dispatch<React.SetStateAction<VocabularyWordDto[]>>;
}) {
  return (
    <>
      <div className={styles.filters}>
        <Field className={styles.searchInput} placeholder="Search words..." value={search} onChange={(e) => setSearch(e.target.value)} />
        <SegmentedControl
          value={filter}
          onValueChange={setFilter}
          ariaLabel="Vocabulary categories"
          className={styles.catFilters}
          optionClassName={styles.catBtn}
          activeOptionClassName={styles.catActive}
          options={categories.map((category) => ({
            value: category,
            label: category.charAt(0).toUpperCase() + category.slice(1),
          }))}
        />
      </div>

      <div className={styles.wordGrid}>
        {filtered.map((word, i) => (
          <div key={word.id} className={styles.wordCard} style={{ animationDelay: `${i * 0.03}s` }}>
            <div className={styles.wcTop}>
              <div>
                <div className={styles.wcWord}>{word.word}</div>
                <div className={styles.wcPhonetic}>{word.phonetic}</div>
              </div>
              <Badge className={`${styles.wcStatus} ${styles[word.status === 'new' ? 'blue' : word.status === 'learning' ? 'amber' : 'green']}`} variant={word.status === 'new' ? 'blue' : word.status === 'learning' ? 'amber' : 'green'}>
                {word.status}
              </Badge>
            </div>
            <div className={styles.wcPos}>{word.pos}</div>
            <div className={styles.wcDef}>{word.definition}</div>
            <div className={styles.wcExample}>&quot;{word.example}&quot;</div>
            <div className={styles.wcActions}>
              {(['new', 'learning', 'known'] as const).map((status) => (
                <Button
                  type="button"
                  key={status}
                  className={`${styles.wcBtn} ${word.status === status ? styles.wcBtnActive : ''}`}
                  onClick={() => setWords((prev) => prev.map((item) => (item.id === word.id ? { ...item, status } : item)))}
                >
                  {status}
                </Button>
              ))}
            </div>
          </div>
        ))}
      </div>
      {filtered.length === 0 ? <EmptyStateCard className={styles.empty} title="No words found" description="Try a different filter." /> : null}
    </>
  );
}

export function VocabularyFlashcardSection({
  cardIndex,
  total,
  currentCard,
  flipped,
  setFlipped,
  markStatus,
  setCardIndex,
}: {
  cardIndex: number;
  total: number;
  currentCard?: VocabularyWordDto;
  flipped: boolean;
  setFlipped: (v: boolean) => void;
  markStatus: (status: VocabularyWordDto['status']) => void;
  setCardIndex: React.Dispatch<React.SetStateAction<number>>;
}) {
  return (
    <div className={`container container--form ${styles.flashcardMode}`}>
      <ProgressHeader className={styles.fcProgress} barClassName={styles.fcBar} fillClassName={styles.fcBarFill} current={cardIndex + 1} total={total} />
      {currentCard ? (
        <>
          <div className={`${styles.flashcard} ${flipped ? styles.flipped : ''}`} onClick={() => setFlipped(!flipped)}>
            <div className={styles.fcFront}>
              <div className={styles.fcHint}>Click to reveal definition</div>
              <div className={styles.fcWord}>{currentCard.word}</div>
              <div className={styles.fcPhonetic}>{currentCard.phonetic}</div>
              <div className={styles.fcCategory}>
                {currentCard.category} · {currentCard.pos}
              </div>
            </div>
            <div className={styles.fcBack}>
              <div className={styles.fcDef}>{currentCard.definition}</div>
              <div className={styles.fcExample}>&quot;{currentCard.example}&quot;</div>
            </div>
          </div>
          {flipped ? (
            <div className={styles.fcButtons}>
              <Button type="button" className={`${styles.fcBtn} ${styles.fcBtnRed}`} onClick={() => markStatus('new')}>Still learning</Button>
              <Button type="button" className={`${styles.fcBtn} ${styles.fcBtnAmber}`} onClick={() => markStatus('learning')}>Almost got it</Button>
              <Button type="button" className={`${styles.fcBtn} ${styles.fcBtnGreen}`} onClick={() => markStatus('known')}>Know it! ✓</Button>
            </div>
          ) : null}
          <div className={styles.fcNav}>
            <Button type="button" className={styles.fcNavBtn} onClick={() => { setCardIndex((i) => Math.max(0, i - 1)); setFlipped(false); }} disabled={cardIndex === 0}>← Prev</Button>
            <Button type="button" className={styles.fcNavBtn} onClick={() => { setCardIndex((i) => Math.min(total - 1, i + 1)); setFlipped(false); }} disabled={cardIndex === total - 1}>Next →</Button>
          </div>
        </>
      ) : (
        <EmptyStateCard className={styles.fcComplete} icon={<div className={styles.fcCompleteIcon}>🎉</div>} title={<div className={styles.fcCompleteTitle}>All done!</div>} description={<div className={styles.fcCompleteSub}>You reviewed all {total} words. Great work!</div>} />
      )}
    </div>
  );
}
